// Filter: Should Respond
// Returns items that should get a response; drops the rest.

const raw = $input.item.json;

// Ignore messages from bots
if (raw.author && raw.author.bot) {
  return [];
}

// Ignore empty messages
if (!raw.content && (!raw.attachments || raw.attachments.length === 0)) {
  return [];
}

const isDM = !raw.guildId;
const isEdit = !!raw.editedTimestamp;

// Check if bot is @mentioned in servers
// Discord encodes mentions as <@BOT_ID> in message content
const botIdPattern = /<@\d+>/;
const isMentioned = botIdPattern.test(raw.content || '');

if (isDM) {
  // DMs: always respond (new messages and edits)
  return [{ json: { ...raw, _shouldRespond: true, _isDM: true, _isEdit: isEdit } }];
}

// Server messages
if (isEdit) {
  // Edits in servers: only respond if bot is @mentioned
  if (isMentioned) {
    return [{ json: { ...raw, _shouldRespond: true, _isDM: false, _isEdit: true } }];
  }
  // Edit without @mention: drop
  return [];
}

// New server messages: only respond if bot is @mentioned
if (isMentioned) {
  return [{ json: { ...raw, _shouldRespond: true, _isDM: false, _isEdit: false } }];
}

// Server message without @mention: drop
return [];

// Normalize Message — Discord to internal schema
// Strips <@BOT_ID> mention syntax from message_text so AI doesn't see raw mention syntax.

const raw = $input.item.json;

// Discord trigger emits flat authorId/authorName fields (not nested under author object)
const normalized = {
  source_channel: "discord",
  channel_id: raw.channelId || raw.channel_id || '',
  guild_id: raw.guildId || null,
  user_id: raw.authorId || (raw.author && raw.author.id) || 'unknown',
  username: raw.authorName || (raw.author && (raw.author.globalName || raw.author.username)) || 'unknown',
  message_text: (raw.content || '').replace(/<@\d+>/g, '').trim(),
  message_id: raw.id || raw.message_id || '',
  is_dm: !raw.guildId,
  conversation_privacy: raw.guildId ? 'public' : 'private',
  is_mention: raw._isDM ? false : /<@\d+>/.test(raw.content || ''),
  is_edit: raw._isEdit || !!raw.editedTimestamp,
  attachments: (raw.attachments || []).map(function(a) {
    return {
      type: a.contentType || 'unknown',
      size: a.size || 0,
      url: a.url || null,
      filename: a.name || a.filename || 'unknown'
    };
  }),
  timestamp: raw.createdTimestamp || Date.now(),
  session_key: 'discord_' + (raw.channelId || raw.channel_id || 'unknown')
};

return [{ json: normalized }];

// Merge person_id from identity resolver back into the original message payload
// $('Restore Context') has the normalized message with all fields
// $input has the resolver output (person_id, display_name, is_new)

const resolverOutput = $input.item.json;
const originalMsg = $('Inject Location Label').item.json;

return [{
  json: {
    ...originalMsg,
    person_id: resolverOutput.person_id,
    display_name: resolverOutput.display_name
  }
}];

const channelName = $input.item.json.channel_name || 'unknown';
const ctx = $('Restore Context').item.json;
return [{
  json: {
    ...ctx,
    channel_name: channelName,
    location_label: 'Discord — The Resonant Span / ' + channelName
  }
}];

// Snowflake to Date helper
function snowflakeToDate(id) {
  try { return new Date(Number((BigInt(id) >> 22n)) + 1420070400000); }
  catch { return null; }
}

const items = $input.all();
// HTTP Request returns the messages array directly as one item with json being the array
// or as multiple items (one per message) - handle both cases
let msgs = [];
if (items.length === 1 && Array.isArray(items[0].json)) {
  msgs = items[0].json;
} else {
  msgs = items.map(i => i.json);
}

// Get the triggering message context from Normalize Message node
const trigMsg = $('Normalize Message').item.json;
const trigId = trigMsg.message_id || trigMsg.id;
const triggerTime = trigMsg.timestamp ? new Date(trigMsg.timestamp) : new Date();

function nameOf(m) {
  return m.author?.global_name || m.author?.username || m.username || 'Unknown';
}
function msgDate(m) {
  if (m.timestamp) return new Date(m.timestamp);
  if (m.id) return snowflakeToDate(m.id);
  return null;
}

// Filter: all messages (humans AND bots), before trigger time, not the triggering message.
const roomMsgs = msgs.filter(m => {
  const hasText = (m.content ?? '').trim().length > 0;
  const mt = msgDate(m);
  const beforeTrigger = mt ? (mt <= triggerTime) : true;
  const notWake = m.id !== trigId;
  return hasText && beforeTrigger && notWake;
});

// Participant summary header
const speakerCounts = {};
roomMsgs.forEach(m => {
  const name = nameOf(m);
  speakerCounts[name] = (speakerCounts[name] || 0) + 1;
});
const participantSummary = Object.keys(speakerCounts).length > 0
  ? `PARTICIPANTS: ${Object.entries(speakerCounts).sort((a,b)=>b[1]-a[1]).map(([n,c])=>`${n} (${c})`).join(', ')}\n---\n`
  : '';

// Speaker-tagged transcript (capped at 5800 chars)
function formatTime(date) {
  if (!date) return '';
  return date.toLocaleString('en-US', {
    timeZone: 'America/New_York',
    month: 'short', day: 'numeric',
    hour: 'numeric', minute: '2-digit',
    hour12: true, timeZoneName: 'short'
  }); // -> "Feb 26, 2:34 PM EST"
}
const lines = roomMsgs.map(m => {
  const t = msgDate(m);
  const timeStr = t ? ` (${formatTime(t)})` : '';
  return `[${nameOf(m)}${timeStr}]: ${m.content.trim()}`;
});
const transcript = (participantSummary + lines.join('\n')).slice(0, 5800);

return [{ json: { thread_context: transcript || '' } }];

const items = $input.all();
// HTTP Request returns members array - handle both array and multiple items
let members = [];
if (items.length === 1 && Array.isArray(items[0].json)) {
  members = items[0].json;
} else {
  members = items.map(i => i.json);
}
const memberMap = {};
members.forEach(m => {
  const userId = m.user?.id || m.id;
  const displayName = m.nick || m.user?.global_name || m.user?.username || 'Unknown';
  if (userId) memberMap[userId] = displayName;
});
const memberListText = Object.entries(memberMap)
  .map(([id, name]) => `<@${id}>: ${name}`)
  .join('\n');
return [{ json: { member_list: memberListText, member_map: memberMap } }];

// Both Build Thread Context and Format Member List arrive as items on input 0
// Merge Context (append mode) concatenates them — find each by its fields
const items = $input.all();
const threadCtx = items.find(i => i.json.thread_context !== undefined)?.json || {};
const memberCtx = items.find(i => i.json.member_list !== undefined)?.json || {};
const original = $('Normalize Message').item.json;
return [{
  json: {
    ...original,
    thread_context: threadCtx.thread_context || '',
    member_list: memberCtx.member_list || '',
    member_map: memberCtx.member_map || {}
  }
}];

const input = $input.first().json;
return [{
  json: {
    person_id: input.person_id,
    channel_id: input.channel_id || input.session_key,
    message_text: input.message_content || input.message_text || input.content || '',
    privacy_context: input.conversation_privacy || (input.is_dm ? 'private' : 'public')
  }
}];

const memResult = $input.first().json;
const original = $('Build Thread Context (Guild)').item.json;
return [{
  json: {
    ...original,
    memory_context: memResult.memory_context || ''
  }
}];

const profileResp = $input.first().json;
const original = $('Merge Memory Result').item.json;
const profileData = profileResp.profile || {};
const lines = profileData.lines || [];
const coldStart = profileData.cold_start || false;

const profileContext = lines.length > 0
  ? lines.join('\n')
  : '';

return [{
  json: {
    ...original,
    profile_context: profileContext,
    cold_start: coldStart
  }
}];

// Build timestamped thread context from n8n_chat_histories
// Receives N items (one per DB row); outputs 1 item with thread_context injected

const rows = $input.all();
const upstream = $('Merge person_id').item.json;

// Filter out sentinel, nulls, and any error rows
const validRows = rows.filter(r =>
  r.json.role !== 'sentinel' &&
  r.json.content !== null &&
  r.json.content !== undefined &&
  !r.json.error
);

let thread_context = null;

if (validRows.length > 0) {
  // Sort chronologically (query returned DESC)
  const sorted = validRows.sort((a, b) =>
    new Date(a.json.created_at) - new Date(b.json.created_at)
  );

  const displayName = upstream.display_name || upstream.username || 'User';

  const lines = sorted.map(r => {
    const ts = new Date(r.json.created_at);
    const formatted = ts.toLocaleString('en-US', {
      timeZone: 'America/New_York',
      month: 'short', day: 'numeric',
      hour: 'numeric', minute: '2-digit',
      hour12: true, timeZoneName: 'short'
    });
    const speaker = r.json.role === 'human' ? displayName : 'Aerys';
    const content = (r.json.content || '').trim();
    const snippet = content.length > 300 ? content.substring(0, 300) + '...' : content;
    return `[${formatted}] ${speaker}: ${snippet}`;
  });

  thread_context = lines.join('\n');
}

return [{
  json: {
    ...upstream,
    thread_context: thread_context || upstream.thread_context || null
  }
}];

